import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"五龙亭","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/wulongting.md","filePath":"landmarks/beihai/wulongting.md","lastUpdated":1784720050000}'),n={name:"landmarks/beihai/wulongting.md"};function o(i,t,s,g,d,h){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="五龙亭" tabindex="-1">五龙亭 <a class="header-anchor" href="#五龙亭" aria-label="Permalink to &quot;五龙亭&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1714216818377-1a2f17142ea5?w=1200&amp;q=80" alt="五龙亭"></p><blockquote><p>五座方亭凌波而立，以飞桥相连，如五条游龙蜿蜒水面——这是北海北岸最灵动的一幅&quot;水殿&quot;图景。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>五龙亭</strong>位于北海北岸、太液池西畔，是五座临水而筑、以桥相连的<strong>水上方亭</strong>，始建于<strong>明嘉靖年间</strong>，清代屡有修缮。五亭东西排列、一字排开于碧波之上，中亭最高、两侧递降，以曲折的飞桥彼此勾连，远望如五条游龙戏水，故得名&quot;五龙亭&quot;。</p><p>五龙亭是昔日<strong>帝王垂钓、赏月、观焰火</strong>之所。每至节庆良宵，湖上灯火与焰火齐放，皇帝端坐亭中，隔水眺望对岸琼华岛白塔的夜色，是北海最富皇家气韵的游赏场景。今日的五龙亭已对公众开放，是游客临水品茗、观湖赏景的绝佳去处。</p><p>五龙亭的设计，是中国古典园林&quot;因水成景、借水造境&quot;的典范。亭不在山、不依墙，而直接凌于水面之上，让建筑与水、与天、与对岸的白塔融为一体。人立亭中，如置身湖心，四面皆水景，这种&quot;水殿&quot;式的营造手法，在皇家园林中极为难得。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">明嘉靖年间</td><td style="text-align:left;">始建五座水亭，初为帝后游宴之所</td></tr><tr><td style="text-align:left;">清代</td><td style="text-align:left;">屡经修缮，成为帝王垂钓、观焰火之地</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">对公众开放，设茶座，为临水观景佳处</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">亭名</th><th style="text-align:center;">位置</th><th style="text-align:left;">规格特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>龙泽亭</strong></td><td style="text-align:center;">居中</td><td style="text-align:left;">五亭之主，重檐攒尖方顶，体量最大、等级最高</td></tr><tr><td style="text-align:left;"><strong>澄祥亭</strong></td><td style="text-align:center;">中亭左（东）</td><td style="text-align:left;">单檐方亭</td></tr><tr><td style="text-align:left;"><strong>涌瑞亭</strong></td><td style="text-align:center;">澄祥亭东</td><td style="text-align:left;">单檐方亭</td></tr><tr><td style="text-align:left;"><strong>滋香亭</strong></td><td style="text-align:center;">中亭右（西）</td><td style="text-align:left;">单檐方亭</td></tr><tr><td style="text-align:left;"><strong>浮翠亭</strong></td><td style="text-align:center;">滋香亭西</td><td style="text-align:left;">单檐方亭</td></tr></tbody></table><p>五亭之中，<strong>龙泽亭</strong>居中，为五亭之主，采用<strong>重檐攒尖方顶</strong>，顶覆琉璃瓦、四角飞翘，宝顶居中，是昔日皇帝垂钓与观焰火的主亭；左右对称的<strong>澄祥、滋香、涌瑞、浮翠</strong>四亭则为单檐方亭，体量略小、簇拥主亭，形成众星拱月之势。五亭皆以<strong>琉璃瓦顶</strong>、朱柱彩绘装饰，并以<strong>飞桥（石/木曲桥）相连</strong>，曲折凌波，既便于通行，又构成起伏有致的轮廓线。</p><p>亭前开阔的水面正对琼华岛白塔，是隔水观赏白塔倒影的最佳视点之一。凭栏而立，水风拂面，白塔、红墙、绿树尽收一湖之中。黄昏时分，夕阳洒于琉璃瓦顶，与湖水相映成金色，是北海最动人的画面之一。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="帝王垂钓与湖上焰火" tabindex="-1">帝王垂钓与湖上焰火 <a class="header-anchor" href="#帝王垂钓与湖上焰火" aria-label="Permalink to &quot;帝王垂钓与湖上焰火&quot;">​</a></h3><p>五龙亭在明清两代是帝后消夏游乐的重要场所。史载帝王常在此<strong>垂钓</strong>，临水静坐、抛竿待鱼，享一份难得的闲适。而更热闹的，则是节庆之夜的<strong>湖上焰火</strong>——每当元宵、万寿等佳节，北海湖上燃放焰火，皇帝便端坐龙泽亭中，隔水欣赏对岸琼华岛前的火树银花，亭台、湖水与焰火交相辉映，构成皇家苑囿中最华美的一幕。从垂钓的静谧到焰火的喧腾，五龙亭见证了帝王生活的两面。</p><h3 id="五亭命名的讲究" tabindex="-1">五亭命名的讲究 <a class="header-anchor" href="#五亭命名的讲究" aria-label="Permalink to &quot;五亭命名的讲究&quot;">​</a></h3><p>五亭之名——龙泽、澄祥、涌瑞、滋香、浮翠——皆取自祥瑞与自然的意象。&quot;龙泽&quot;喻帝王恩泽如龙润物，&quot;澄祥&quot;&quot;涌瑞&quot;寓意祥瑞澄明、瑞气涌动，&quot;滋香&quot;&quot;浮翠&quot;则描摹草木芬芳、碧波浮翠的湖上风光。五名合观，既颂皇恩，又写水景，是皇家园林命名&quot;寓情于景&quot;的典型，也让这组水亭在实用之外，多了一层文人雅趣。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>五亭凌波</strong>：远观五亭以飞桥相连、一字排开的轮廓，如游龙戏水，是北海北岸最具辨识度的天际线。</li><li><strong>龙泽亭重檐</strong>：近看居中龙泽亭的重檐攒尖顶与琉璃瓦，体会其高出四亭的&quot;主亭&quot;规制。</li><li><strong>飞桥漫步</strong>：沿曲桥在亭间穿行，移步换景，感受&quot;人在水上行&quot;的园林意趣。</li><li><strong>隔水望白塔</strong>：在亭中凭栏远眺，是隔太液池观赏琼华岛白塔倒影的绝佳角度。</li><li><strong>日落与夜景</strong>：黄昏时分夕阳洒于琉璃瓦顶，与湖水相映，是北海最美的时刻之一。</li><li><strong>亭名雅意</strong>：品味五亭&quot;龙泽、澄祥、涌瑞、滋香、浮翠&quot;的命名，体会皇家园林的文学意蕴。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>对岸全景</strong>：从湖对岸远观五亭凌波的全貌，飞桥相连如游龙，是最经典的角度。</li><li><strong>亭中框景</strong>：在亭内以廊柱、栏杆为框，拍摄对岸白塔与湖面，层次丰富。</li><li><strong>黄昏剪影</strong>：日落时分拍摄琉璃瓦顶的暖金色与湖面倒影，氛围感极佳。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>远观与近游结合</strong>：先在湖对岸或岸边远观五亭全貌，再登亭近赏，两种视角各有其妙。</li><li><strong>黄昏最佳</strong>：日落前后的光线最宜拍摄琉璃瓦顶与湖水倒影，也最清凉宜人。</li><li><strong>临水品茗</strong>：亭中常设茶座，不妨坐下小憩，临水观湖，体会帝王昔日的闲适。</li><li><strong>联游北岸</strong>：五龙亭与<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>、<a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a>同在北海北岸，可沿湖串联。</li><li><strong>对望琼岛</strong>：在五龙亭回望<a href="/beijing-travel-guide/landmarks/beihai/baita.html">琼华岛白塔</a>，是隔水观景的经典角度，别错过。</li><li><strong>注意安全</strong>：亭与桥皆临水，带小孩或拍照时留意脚下，勿攀越栏杆。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：五龙亭为什么叫&quot;五龙&quot;？</strong></p><p>五亭凌波一字排开，中亭（龙泽亭）最高、两侧递降，以飞桥相连，远望如五条游龙蜿蜒水面，故得名&quot;五龙亭&quot;。居中的龙泽亭是昔日皇帝专属的主亭。</p><p><strong>Q：可以进亭子休息吗？</strong></p><p>可以。五龙亭已对公众开放，亭中常设茶座，游客可以入内临水品茗、歇脚观景，是北海最惬意的休憩处之一。</p><p><strong>Q：什么时候去五龙亭最美？</strong></p><p>推荐黄昏。日落前后夕阳洒在琉璃瓦顶上，与湖面相映成金色，既宜拍照也最清凉；节庆夜晚若能遇上湖上灯影，更可见当年皇家焰火的遗韵。</p><hr><p><strong>📍 位置</strong>：北海北岸西段，太液池西畔 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>（北岸相邻） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>、<a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a>（北岸向东） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/beihai/">北海公园概览</a></p>',33)])])}const q=a(n,[["render",o]]);export{b as __pageData,q as default};
